import{_ as i,c as a,o as s,ae as e}from"./chunks/framework.Dh1jimFm.js";const h=JSON.parse('{"title":"记录学习PHP过程中遇到的各种API、常量等","description":"","frontmatter":{},"headers":[],"relativePath":"document/PHP.md","filePath":"document/PHP.md"}'),n={name:"document/PHP.md"};function t(p,l,r,c,o,u){return s(),a("div",null,l[0]||(l[0]=[e(`<h1 id="记录学习php过程中遇到的各种api、常量等" tabindex="-1">记录学习PHP过程中遇到的各种API、常量等 <a class="header-anchor" href="#记录学习php过程中遇到的各种api、常量等" aria-label="Permalink to &quot;记录学习PHP过程中遇到的各种API、常量等&quot;">​</a></h1><h2 id="php-api" tabindex="-1">PHP API <a class="header-anchor" href="#php-api" aria-label="Permalink to &quot;PHP API&quot;">​</a></h2><ul><li>addslashes 使用反斜线引用字符串， <ul><li>addslashes(string $str):string 返回字符串，该字符串为了数据库查询语句等的需要在某些字符前加上了反斜线。</li><li>这些字符包括：单引号(&#39;)、双引号(&quot;)、反斜线() 与 NUL(null字符)。</li></ul></li><li>htmlspecialchars <ul><li>htmlspecialchars -- 将特殊字符串转为 HTML 实体</li><li>某类字符在 HTML 中有特殊用处，如需保持愿意，需要用 HTML 实体来表达</li><li>htmlspecialchars_decode -- 将特殊的 HTML 实体转换回普通字符</li></ul></li><li>intval 获取变量的整数值 <ul><li>intval(mixed $value,int $base = 10):int 第二个参数是要转换成的进制数</li></ul></li><li>strlen 获取一个字符串的长度 <ul><li>strlen( string $string ):int</li><li>返回给定字符串 string 的长度</li></ul></li><li>explode 使用一个字符串分割另一个字符串</li><li>implode 将一个一维数组的值转化为字符串</li><li>str_replace 字符串替换 <ul><li>str_replace( mixed $search,mixed $replace,mixed $subject,int $count = ?):mixed</li><li>该函数返回一个字符串或者数组。改字符串或数组是将 subject 中全部的 search 都被 replace 替换后的结果。count可选参数，是值被替换发生的次数。</li><li>如果没有特殊替换要求，应该使用该函数替换 ereg_replace() 和 preg_replace()</li></ul></li><li>strpos 查找字符串首次出现的位置</li><li>sprintf() 函数 <ul><li>把百分号(%)符号替换成一个作为参数进行传递的变量<div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  &lt;?php </span></span>
<span class="line"><span>    $number = 2;</span></span>
<span class="line"><span>    $str = &quot;ShangHai&quot;;</span></span>
<span class="line"><span>    $txt = sprintf(&quot;There are %u million cars in %s.&quot;,$number,$str);</span></span>
<span class="line"><span>    echo $txt;</span></span>
<span class="line"><span>  ?&gt;</span></span></code></pre></div></li></ul></li><li>array_map()函数 -- 为数组的每个元素应用回调函数 <ul><li>array_map( callback $callback, array $array, array ...$arrays ):array</li><li>返回值为数组数组内容为array1的元素按索引顺序调用 callback 后的结果（有更多数组时，还会传入 arrays 的元素）。callback函数形参的数量必须匹配array_map()实参中数组的数量。<div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  &lt;?php</span></span>
<span class="line"><span>    function show_Spanish ($n,$m)</span></span>
<span class="line"><span>    {</span></span>
<span class="line"><span>      return &quot;The number {$n} is called {$m} in Spanish&quot;;</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>    $a = [1,2,3,4,5];</span></span>
<span class="line"><span>    $b = [&#39;uno&#39;,&#39;dos&#39;,&#39;tres&#39;,&#39;cuatro&#39;,&#39;cinco&#39;];</span></span>
<span class="line"><span>    $c = array_map(&#39;show_Spanish&#39;,$a,$b);</span></span>
<span class="line"><span>    print_r($c);</span></span></code></pre></div><ul><li>array_filter 使用回调函数过滤数组元素</li></ul></li></ul></li><li>get_class 返回对象的类名</li><li>time 返回当前的 Unix 时间戳 -- 返回自 Unix 纪元（格林威治时间 1970年1月1日00:00:00）到当前时间的秒数 <ul><li>microtime 返回当前的 Unix 时间戳 微秒数</li></ul></li><li>json_encode 对变量进行JSON编码</li><li>json_decode 对变量进行JSON解码</li><li>date 格式化一个本地时间/日期</li><li>is_numeric 检测变量是否为数字或数字字符串</li><li>defined 检测某个名称的 常量 是否存在 <ul><li>defined( string $name ):bool</li><li>如果要检查一个变量是否存在，请使用 isset()</li><li>defined() 函数仅对constants（常量）有效</li><li>如果要检测某个函数是否存在，请使用 function_exists()</li><li>如果要检测一个类的某个方法是否存在，可以用 method_exists</li></ul></li><li>header 发送原生 HTTP 头 <ul><li>header( string $string, bool $replace = true, int $http_response_code = ?):void</li><li>注意 hearder() 必须在任何实际输出之前调用，不管是普通HTML标签，还是文件或PHP输出的空行、空格。</li><li>携带的信息参数可以是单一字符串，中间以冒号分别则在请求头里面显示未键值对</li></ul></li><li>file_put_contents 将一个字符串写入文件 --- 没调用成功 <ul><li>file_put_content(string $filename, mixed $data, int $flags = 0,resource $context = ?):int</li><li>和一次调用 fopen()、fwrite()、fclose() 功能一样</li><li>$data 是要写入的数据。类型可以使 string、array或者是 stream资源</li><li>file_get_contents 获取已存在的目录文件的内容</li></ul></li><li>basename 返回路径中的文件名部分 <ul><li>dirname 返回路径中的文件名部分</li><li>pathinfo 返回文件路径的信息</li><li>realpath 返回规范化的绝对路径名 --- 没有输出</li></ul></li><li>fopen 打开文件或者URL，将filename指定的名字资源绑定到一个流上 <ul><li>fwrite</li><li>fclose 关闭一个已打开的文件指针</li></ul></li><li>is_int 检测变量是否是整数 <ul><li>is_file 判断给定文件名是否为一个正常的文件</li><li>is_callable 检测一个函数是不是可用的回调函数</li></ul></li><li>unlink 删除文件 <ul><li>unlink(string $filename, resource $context=?):bool</li><li>删除filename，成功时返回 true，失败返回 false</li></ul></li><li>call_user_func 把第一个参数作为回调函数调用，其余参数作为回调函数的参数传入,返回值为回调函数的返回值</li><li>feof(resource $handle) 检测文件指针是否到达文件末尾 <ul><li>如果文件指针到了EOF（文件末尾）或者出错时则返回true，否则返回一个错误（包括 socket 超时），其它情况则返回 false</li><li>feof函数对于遍历长度未知的数据很有效</li></ul></li><li>list() 把数组中的值赋给一组变量 （类似JS的解构赋值） <ul><li>list(mixed $var, ....):array</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  $info = array(&#39;coffee&#39;,&#39;brown&#39;,&#39;caffeine&#39;,);</span></span>
<span class="line"><span>  list($drink, $color, $power) = $info;</span></span></code></pre></div></li><li>fgets 从文件指针中读取一行 <ul><li>fgets(resource $handle, int $length = ?):string</li><li>文件指针$handle必须是有效的, 是通过fopen()或fsockopen()打开的，且没有由fclose()关闭的</li><li>返回读取了 length - 1 字节后返回的字符串，如果指针中没有更多数据了，则返回false，错误发生时，返回false</li></ul></li><li></li><li>preg_match_all 执行一个全局正则表达式匹配</li><li>serialize 返回一个可存储的值的表示</li></ul><h2 id="常量" tabindex="-1">常量 <a class="header-anchor" href="#常量" aria-label="Permalink to &quot;常量&quot;">​</a></h2>`,4)]))}const m=i(n,[["render",t]]);export{h as __pageData,m as default};
